// 1️⃣ Pull rows from Google Sheets and filter out empty ones
const rows = items.filter(i => Object.keys(i.json).length > 0);

// 2️⃣ Count the real messages
const messageCount = rows.length;

// 3️⃣ Pull the original user message from 'Normalize Input'
const original = $node["Normalize Input"].json;

// 4️⃣ Normalize the user message for greeting detection
const msg = (original.user_message || "")
    .toLowerCase()
    .trim()
    .replace(/[^\w\s]/g, "")   // remove punctuation (! ? . , etc.)
    .replace(/\s+/g, " ");     // normalize spaces

// 5️⃣ Define greetings
const greetings = [
    "hi",
    "hello",
    "hey",
    "good morning",
    "good noon",
    "good afternoon",
    "good evening"
];

// 6️⃣ Detect if the message is a greeting (e.g., "hi!", "hello bro!")
const greetingDetected = greetings.some(greeting => msg === greeting || msg.startsWith(greeting + " "));

// 7️⃣ Return all data
return [
    {
        json: {
            ...original,               // keep original user message and other fields
            message_count: messageCount,
            chat_history: rows,        // all previous messages
            greeting_detected: greetingDetected // true/false
        }
    }
];

// Pull and normalize the user message
const msg = ($json.user_message || "")
    .toLowerCase()
    .trim()
    .replace(/[^\w\s]/g, "")  // remove punctuation (! ? . , etc.)
    .replace(/\s+/g, " ");    // normalize spaces

// List of greetings to detect
const greetings = [
    "hi",
    "hello",
    "hey",
    "good morning",
    "good noon",
    "good afternoon",
    "good evening"
];

// Check if message is exactly a greeting or starts with one
const isGreeting = greetings.some(greeting => msg === greeting || msg.startsWith(greeting + " "));

// Return the flag along with the original JSON
return [
    {
        json: {
            ...$json,
            greeting_detected: isGreeting // ✅ true or false
        }
    }
];

const aiReply = $json.choices?.[0]?.message?.content?.trim();

const fallbackReply = "Sorry 😅, I’m here to answer questions about Sheikh Mainul Islam’s projects . Let me know if you have anything related.";

return [
  {
    json: {
      ...$node["Normalize Input"].json,
      reply: aiReply && aiReply !== "" ? aiReply : fallbackReply
    }
  }
];

const sessionId = ($json.body.session_id || "").trim();
const message = ($json.body.user_message || "").toLowerCase().trim();

return [{
  json: {
    session_id: sessionId,
    user_message: message,
    lead_name: "visitor_" + sessionId,
    timestamp: new Date().toISOString()
  }
}];

// Pull the original user message directly from the 'Normalize Input' node
const userMessage = ($('Normalize Input').first().json.user_message || "").toLowerCase();

let reply;

if (userMessage.includes("hi")) {
    reply = "Hi! 😊 I’m Sheikh Mainul Islam. How can I help you today?";
} else if (userMessage.includes("hello")) {
    reply = "Hello! 😊 I’m Sheikh Mainul Islam. How can I help you today?";
} else if (userMessage.includes("hey")) {
    reply = "Hey! 👋 I’m Sheikh Mainul Islam. How’s your day going?";
} else if (
    userMessage.includes("good morning") ||
    userMessage.includes("good afternoon") ||
    userMessage.includes("good evening") ||
    userMessage.includes("good noon")
) {
    const timeOfDayMatch = userMessage.match(/morning|afternoon|evening|noon/);
    const timeOfDay = timeOfDayMatch ? timeOfDayMatch[0] : "";
    reply = `Good ${timeOfDay}! 😊 I’m Sheikh Mainul Islam. How can I assist you today?`;
} else {
    reply = "Hello! 👋 I’m Sheikh Mainul Islam. How can I help you today?";
}

// Return the reply and keep the rest of the JSON intact
return [
    {
        json: {
            ...$json,
            reply // ✅ IMPORTANT: pass forward
        },
    },
];

const rows = items;
const currentMessage = ($json.user_message || "").toLowerCase().trim();

if (!rows || rows.length === 0) {
  return [{ json: { history: "", last_user_message: "" } }];
}

// 👉 Sort by timestamp (VERY IMPORTANT)
const sorted = rows.sort((a, b) => {
  return new Date(a.json.timestamp) - new Date(b.json.timestamp);
});

let filtered = [];

for (const item of sorted) {
  const msg = (item.json.user_message || "").toLowerCase().trim();

  // ❌ Skip current message
  if (msg === currentMessage) continue;

  // ❌ Skip meta questions
  if (
    msg.includes("what was my last message") ||
    msg.includes("previous message") ||
    msg.includes("what did i say")
  ) continue;

  // ❌ Skip greetings
  if (msg === "hi" || msg === "hello") continue;

  filtered.push(msg);
}

// Keep last 10
const lastMessages = filtered.slice(-10);

// 👉 Get LAST meaningful message (CRITICAL)
const lastMessage = lastMessages.length > 0
  ? lastMessages[lastMessages.length - 1]
  : "";

// Format history
const historyText = lastMessages.map(m => `User: ${m}`).join("\n");

return [
  {
    json: {
      history: historyText,
      last_user_message: lastMessage
    }
  }
];
